class Solution:
    def minimumMoney(self, transactions):
        total_loss = sum(max(0, c - b) for c, b in transactions)
        best = 0
        for c, b in transactions:
            own = max(0, c - b)
            need = total_loss - own + c
            if need > best:
                best = need
        return best

