class Solution:
    def minimumMoney(self, transactions):
        loss = 0
        for c, b in transactions:
            if c > b:
                loss += c - b
        ans = 0
        for c, b in transactions:
            if c > b:
                ans = max(ans, loss - (c - b) + c)
            else:
                ans = max(ans, loss + c)
        return ans

