var minimumMoney = function(transactions) {
    let loss = 0;
    for (const [c, b] of transactions) {
        if (c > b) loss += c - b;
    }
    let ans = 0;
    for (const [c, b] of transactions) {
        const need = (c > b) ? (loss - (c - b) + c) : (loss + c);
        if (need > ans) ans = need;
    }
    return ans;
};
